  coaching_execution = '{"movement_description":"The athlete hops laterally from one leg or two legs to a target and holds a quiet landing before resetting.","setup":["Use a flat, forgiving surface with enough space to land and reset.","Mark the start or target distance only as far as the athlete can control cleanly.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Lateral Hop to Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"athlete_cues":["Move fast, land quiet, and reset.","The rep only counts if you own the position."],"breathing_cues":["Brace before the contact or release.","Exhale sharply without collapsing posture."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."],"quality_gate":["No pain during takeoff, landing, contact, or release.","Contact sound stays quiet and consistent.","Alignment is repeatable from the first rep to the last rep.","Output stays crisp without visible hesitation or fatigue leakage.","The athlete can stop and reset on command."],"stop_signs":["Pain, sharp discomfort, or loss of confidence appears.","Landing gets louder or uncontrolled for two reps in a row.","Knee, hip, trunk, shoulder, or wrist position becomes unsafe.","Output speed, height, distance, or release velocity clearly drops.","The athlete starts racing the drill or treating it as conditioning."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration or sprint work","Lower-body strength","Sport-skill or technical power block"],"pairs_well_after":["Dynamic warm-up","Landing prep or low-level pogo progression","Relevant mobility/access work"],"good_for_sessions":["landing_prep","control_landing","deceleration"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears with takeoff, landing, contact, bracing, or throw release.","The athlete cannot control the lower-level progression.","The surface, footwear, spacing, or equipment setup is unsafe.","The athlete is already fatigued enough that contacts are slow, loud, or poorly aligned."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Vortex Exercise Card Authoring Guide: Output phase and plyometric sequencing rules","NSCA-style plyometric landing, contact-quality, and full-recovery coaching reference","Internal Vortex demo recommended: front and side views with slow-motion contact review"],"internal_notes":["Film Lateral Hop to Stick from front and side when possible.","Approve progression only when contacts are quiet, posture is repeatable, and the athlete resets without rushing.","Review local taxonomy/slot keys before database import; authoring keys are normalized to exercise_card_details_for_llm.md."]}'::jsonb,
