  coaching_execution = '{"movement_description":"The athlete hinges with a light ball between the legs, rapidly extends the hips, and throws the ball forward or upward.","setup":["Choose a light medicine ball that can be thrown fast without trunk leakage.","Use a safe wall, open lane, or trained partner depending on the throw direction.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Medicine Ball Scoop Toss with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Light ball, fast release.","Throw through the target.","Hips then hands.","Brace and finish tall.","Reset before the next rep."],"athlete_cues":["Move fast, land quiet, and reset.","The rep only counts if you own the position."],"breathing_cues":["Brace before the contact or release.","Exhale sharply without collapsing posture."],"common_faults":["Using a ball that is too heavy for speed.","Leaking through the low back or ribs during the throw.","Rotating or pressing from the arms only instead of using the whole body.","Standing too close to the wall or throwing into an unsafe lane.","Rushing reps until release speed fades."],"quality_gate":["No pain during takeoff, landing, contact, or release.","Contact sound stays quiet and consistent.","Alignment is repeatable from the first rep to the last rep.","Output stays crisp without visible hesitation or fatigue leakage.","The athlete can stop and reset on command."],"stop_signs":["Pain, sharp discomfort, or loss of confidence appears.","Landing gets louder or uncontrolled for two reps in a row.","Knee, hip, trunk, shoulder, or wrist position becomes unsafe.","Output speed, height, distance, or release velocity clearly drops.","The athlete starts racing the drill or treating it as conditioning."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Pressing strength","Throwing skill work","Sport-skill practice"],"pairs_well_after":["Shoulder and trunk prep","Scapular or wrist readiness","Low-fatigue activation"],"good_for_sessions":["power_development","deceleration","court_field_power"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears with takeoff, landing, contact, bracing, or throw release.","The athlete cannot control the lower-level progression.","The surface, footwear, spacing, or equipment setup is unsafe.","The athlete is already fatigued enough that contacts are slow, loud, or poorly aligned."]}'::jsonb,
