);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for plyometrics: elastic stiffness, landing control, and explosive contacts while fresh.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('snap-down-to-stick', 'It creates a low-threat entry point for teaching foot pressure, knee tracking, trunk stiffness, and controlled force absorption before higher-output jumps.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot landing_deceleration keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('squat-jump-to-stick', 'It connects basic vertical force production to landing ownership, making it an ideal bridge from landing prep to true power work.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot vertical_power_to_stick keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('broad-jump-to-stick', 'It biases horizontal force and acceleration-style projection while requiring the athlete to own the landing instead of simply chasing distance.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot horizontal_power_to_stick keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('lateral-hop-to-stick', 'It exposes the braking strategy athletes need for cutting, shuffling, and redirection while keeping speed and distance adjustable.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot lateral_landing_deceleration keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('single-leg-hop-to-stick', 'It reveals right-left gaps in stiffness and control while training a key quality for sprinting, cutting, and return-to-jump progressions.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot single_leg_hop_to_stick keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('drop-landing-to-stick', 'Removing the takeoff lets the coach isolate landing mechanics, braking timing, and foot pressure before adding rebound or greater height.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot drop_landing_deceleration keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('depth-drop-to-athletic-stick', 'It introduces greater eccentric demand while still keeping the task coachable and non-reactive.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot depth_drop_to_stick keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('star-hop-to-stick', 'The layout exposes directional gaps while keeping amplitude and speed easy to adjust.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot multi_directional_landing_deceleration keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('180-jump-to-stick', 'It layers rotation onto a simple jump so athletes learn to orient and brake without dumping force into the knees or low back.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot rotational_jump_to_stick keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('skater-hop-to-stick', 'It closely matches field and court redirection demands while giving the coach a clear landing-quality checkpoint.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot lateral_bound_to_stick keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
  ('ankle-pogo-in-place', 'It teaches useful stiffness and a fast eccentric-to-concentric transition without requiring large jumps or high landing forces.', 'Belongs in Output because plyometrics primarily express speed, power, elasticity, jumping, throwing, braking, or reactive athleticism while fresh. Slot ankle_stiffness_rudiments keeps it sequenced with drills of similar intent and contact demand.', 'Use after Prepare & Access and any needed Movement Intelligence, while the nervous system is fresh. Program before heavy strength, conditioning, or high-volume sport work, with enough rest that every contact remains high quality.', 'The most common error is chasing fatigue, height, distance, or competition when contact quality has already dropped. Keep volume capped and never place hard plyometrics after conditioning fatigue.', 'Scale by reducing amplitude, contacts, approach speed, direction change, surface hardness, external load, or reactive complexity. Progress only when contacts stay quiet, alignment holds, and output remains crisp.'),
