-- Plyometrics cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'plyometrics_readiness',
  NULL,
  'Plyometrics without conditioning drift or pre-fatigue',
  'Landing mechanics, elastic stiffness, jump power, bounds, depth jumps, and reactive plyometric contacts must stay in Output with high intent, low volume, and full recovery — tired reps are conditioning, not plyometrics.',
  'Plyometrics cards span landing and deceleration sticks, ankle and foot stiffness rudiments, vertical and horizontal jump power, bounds, depth and drop jumps, medicine-ball power, and reactive partner hops for athletes who need elastic force expression while fresh.',
  'Explosiveness and speed qualities score highly only when contacts are fresh, crisp, quiet, and fully recovered. Poor placement, short rest, or high-rep challenges after quality fades raise injury risk and train slow, noisy contacts.',
  'Place after Prepare & Access and any needed Movement Intelligence; use full rest between attempts; stop when landing quality, posture, or contact crispness drops; never place hard plyometrics after conditioning fatigue.',
  'Do not program plyometrics as a finisher or fatigue circuit; do not chase height, distance, or competition when contact quality has already dropped; keep volume capped and progress only when contacts stay quiet.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
